mapper.select:
SELECT d.building_id AS buildingId, d.project_id AS projectId, d.stat_date AS statDate, d.total_shops AS totalShops, d.rented_shops AS rentedShops, d.vacant_shops AS vacantShops, d.opened_shops AS openedShops, d.total_area AS totalArea, d.rented_area AS rentedArea, d.vacant_area AS vacantArea, d.vacancy_rate AS vacancyRate, d.rental_rate AS rentalRate, d.opening_rate AS openingRate FROM rpt_asset_daily d WHERE d.project_id = #{projectId} AND d.building_id > 0 AND d.floor_id = 0 AND d.format_type = '' AND d.is_deleted = 0 AND d.stat_date = ( SELECT MAX(d2.stat_date) FROM rpt_asset_daily d2 WHERE d2.project_id = #{projectId} AND d2.is_deleted = 0
AND d2.stat_date <= #{statDate}
) ORDER BY d.building_id

SELECT d.floor_id AS floorId, d.building_id AS buildingId, d.project_id AS projectId, d.stat_date AS statDate, d.total_shops AS totalShops, d.rented_shops AS rentedShops, d.vacant_shops AS vacantShops, d.opened_shops AS openedShops, d.total_area AS totalArea, d.rented_area AS rentedArea, d.vacant_area AS vacantArea, d.vacancy_rate AS vacancyRate, d.rental_rate AS rentalRate, d.opening_rate AS openingRate FROM rpt_asset_daily d WHERE d.building_id = #{buildingId} AND d.floor_id > 0 AND d.format_type = '' AND d.is_deleted = 0 AND d.stat_date = ( SELECT MAX(d2.stat_date) FROM rpt_asset_daily d2 WHERE d2.building_id = #{buildingId} AND d2.is_deleted = 0
AND d2.stat_date <= #{statDate}
) ORDER BY d.floor_id

SELECT f.project_id AS projectId, f.fee_item_type AS feeItemType, f.accrual_month AS accrualMonth, SUM(f.receivable_amount) AS receivableAmount, SUM(f.received_amount) AS receivedAmount, SUM(f.outstanding_amount) AS outstandingAmount, SUM(f.overdue_amount) AS overdueAmount, CASE WHEN SUM(f.receivable_amount) > 0 THEN ROUND(SUM(f.received_amount) / SUM(f.receivable_amount) * 100, 2) ELSE 0 END AS collectionRate FROM rpt_finance_monthly f WHERE f.project_id = #{projectId} AND f.is_deleted = 0
AND f.accrual_month >= #{startMonth}
AND f.accrual_month <= #{endMonth}
GROUP BY f.project_id, f.fee_item_type, f.accrual_month ORDER BY f.accrual_month DESC, f.fee_item_type

SELECT r.id AS receivableId, r.contract_id AS contractId, r.project_id AS projectId, r.merchant_id AS merchantId, r.fee_item_id AS feeItemId, r.accrual_month AS accrualMonth, r.billing_start AS billingStart, r.billing_end AS billingEnd, r.original_amount AS originalAmount, r.actual_amount AS actualAmount, r.received_amount AS receivedAmount, r.outstanding_amount AS outstandingAmount, r.status AS status FROM fin_receivable r WHERE r.project_id = #{projectId} AND r.is_deleted = 0
AND EXISTS ( SELECT 1 FROM cfg_fee_item fi WHERE fi.id = r.fee_item_id AND fi.charge_type = #{feeItemType} AND fi.is_deleted = 0 )
AND r.accrual_month >= #{startMonth}
AND r.accrual_month <= #{endMonth}
ORDER BY r.accrual_month DESC, r.contract_id LIMIT 500
